// src/pages/superadmin/ApproveGroups.js
import React, { useEffect, useState } from 'react';
import Layout from '../../components/shared/Layout';
import { groupAPI } from '../../services/api';
import toast from 'react-hot-toast';

export default function ApproveGroups() {
  const [groups,  setGroups]  = useState([]);
  const [loading, setLoading] = useState(true);
  const [working, setWorking] = useState('');

  const load = () => {
    groupAPI.getPendingGroups()
      .then(r => setGroups(r.data.data || []))
      .finally(() => setLoading(false));
  };
  useEffect(load, []);

  const handleAction = async (groupId, action, reason = '') => {
    setWorking(groupId + action);
    try {
      await groupAPI.approveGroup({ groupId, action, reason });
      toast.success(`Group ${action === 'APPROVE' ? 'approved! Code generated.' : 'rejected.'}`);
      load();
    } catch (e) { toast.error(e.response?.data?.message || 'Action failed'); }
    finally { setWorking(''); }
  };

  return (
    <Layout>
      <h2 style={{ marginBottom: '0.5rem' }}>Approve Groups</h2>
      <p className="text-grey" style={{ marginBottom: '1.5rem' }}>
        Review and approve or reject group applications from Group Admins.
      </p>

      {loading ? <div className="spinner-wrap"><div className="spinner"/></div> :
       groups.length === 0 ? (
        <div className="empty"><div className="empty-icon">✅</div><h3>No pending groups</h3><p>All caught up!</p></div>
       ) : (
        <div style={{ display:'flex', flexDirection:'column', gap:'1rem' }}>
          {groups.map(g => (
            <div key={g.id} className="card">
              <div className="flex-between" style={{ marginBottom: '0.75rem' }}>
                <div>
                  <h3>{g.name}</h3>
                  <p className="text-grey text-sm">
                    {g.payoutMethod?.replace(/_/g,' ')} •
                    ₹{(g.contributionPerMember * g.maxMembers)?.toLocaleString()} total •
                    {g.maxMembers} members • ₹{g.contributionPerMember}/member
                  </p>
                </div>
                <span className="badge badge-warning">PENDING APPROVAL</span>
              </div>
              <div className="flex gap-1">
                <button
                  className="btn btn-success"
                  disabled={working === g.id+'APPROVE'}
                  onClick={() => handleAction(g.id, 'APPROVE')}>
                  {working === g.id+'APPROVE' ? 'Approving...' : '✓ Approve — Generate Code'}
                </button>
                <button
                  className="btn btn-danger"
                  disabled={working === g.id+'REJECT'}
                  onClick={() => handleAction(g.id, 'REJECT', 'Does not meet platform requirements')}>
                  {working === g.id+'REJECT' ? 'Rejecting...' : '✗ Reject'}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </Layout>
  );
}
